import{_ as e,c as a,o as i,a as o}from"./app.1cfac776.js";const v=JSON.parse('{"title":"Calendario","description":"","frontmatter":{},"headers":[],"relativePath":"ense\xF1anza/calendario.md"}'),s={name:"ense\xF1anza/calendario.md"},n=o('<h1 id="calendario" tabindex="-1">Calendario <a class="header-anchor" href="#calendario" aria-hidden="true">#</a></h1><p>IesApp recoge el calendario escolar del centro y sobre \xE9l se definen los eventos y actividades de manera que su elaboraci\xF3n es un proceso colaborativo y siempre actualizado.</p><p><strong>Eventos</strong></p><ul><li>Los eventos son actividades que involucran a una parte importante del centro y son independientes de los grupos de alumnos: claustro, evaluaci\xF3n, publicaci\xF3n de notas, ...</li><li>Los eventos pueden clasificarse en calendarios: FP, Secundaria, General, ...</li><li>Jefatura de estudios define los eventos.</li></ul><p><strong>Actividades</strong></p><ul><li>Las actividades complementarias son registradas en el calendario por los profesores que las organizan. Las actividades vienen marcadas por: <ul><li>Fecha y hora de inicio y fin.</li><li>Profesores participantes</li><li>Grupos participantes y lista de alumnos que realmente participan.</li><li>Otras informaciones como lugar, persona de contacto, ....</li></ul></li><li>Las actividades deben recibir visto bueno de jefatura para que sean visibles al claustro.</li><li>Si las actividades generan guardias, se crean autom\xE1ticamente a un golpe de click.</li><li>Cuando se da el visto bueno, los profesores que dan clase a los grupos implicados reciben una notificaci\xF3n IesApp.</li><li>Se va a incorporar lo necesario para completar la memoria de actividades de cada departamento.</li></ul>',6),r=[n];function l(t,c,d,p,u,_){return i(),a("div",null,r)}const f=e(s,[["render",l]]);export{v as __pageData,f as default};
